//! Hooks the iced window's WndProc to:
//!   - Detect modal message loops (drag/resize/menu) and pause mpv during them.
//!   - Snap the window to monitor edges during drag (WM_MOVING).
//!   - Snap the window to *other MPV-NE windows* during drag, like PotPlayer
//!     does with multiple instances open - an edge touches the nearest
//!     sibling window's opposite edge (docking side-by-side / stacked).
//!     Siblings are identified by window class name (all MPV-NE windows
//!     share one, generated by winit/iced) rather than process name, so no
//!     process-query APIs are needed. Only considered when the windows
//!     overlap on the perpendicular axis, so it never snaps across the
//!     whole screen to an unrelated window.
//!
//! Uses old-style SetWindowLongPtrW subclassing - no comctl32 v6 / manifest
//! requirement, works on all Windows versions.
#![cfg(target_os = "windows")]

use std::sync::{Mutex, OnceLock};
use std::sync::atomic::{AtomicBool, AtomicI32, AtomicI64, AtomicIsize, AtomicU8, AtomicU32, Ordering};
use std::time::Duration;

type Callback = Box<dyn Fn() + Send + Sync>;

static ON_ENTER:    OnceLock<Callback> = OnceLock::new();
static ON_EXIT:     OnceLock<Callback> = OnceLock::new();
static INSTALLED:   AtomicBool  = AtomicBool::new(false);
/// Original WndProc saved by SetWindowLongPtrW; we chain to it for every
/// message we do not handle ourselves.
static ORIG_WNDPROC: AtomicIsize = AtomicIsize::new(0);

type HWND     = isize;
type HMONITOR = isize;

