const THB_ICON: u32 = 0x2;
const THB_TOOLTIP: u32 = 0x4;
const THB_FLAGS: u32 = 0x8;
const THBF_ENABLED: u32 = 0x0;
const THBN_CLICKED: u32 = 0x1800;
const WM_COMMAND: u32 = 0x0111;

